sql:
SELECT o.name AS OptionName, ov.value AS CurrentValue
FROM options o
INNER JOIN option_values ov ON o.option_id = ov.option_id;

SELECT options.name, options.setting, data_types.type_name
FROM options
INNER JOIN data_types ON options.vartype = data_types.type_id;

SELECT options.name AS Option_Name, categories.category_name AS Category_Name
FROM options
INNER JOIN categories ON options.category = categories.category_id;

SELECT option_id, value, created_at, updated_at
FROM option_values
WHERE created_at != updated_at;

SELECT options.name, option_values.value
FROM options
INNER JOIN option_values ON options.option_id = option_values.option_id;

external_knowledge:
- 'category 0' refers to developer options in this database schema;
- 'accessed but not altered' means the option was reviewed by users but its value remained unchanged;
- 'altered but not accessed' means the option's value was changed, but there are no records of it being viewed after the change;
- 'sorted by their settings and names' means the list will be ordered by the current setting values first, and then alphabetically by option names.

sql:
SELECT DISTINCT u.user_name
FROM users u
JOIN option_history oh ON u.user_id = oh.user_id;
